const ScrollListener={listeners: new Map(),ticking: false,add(id,callback,options={}){const{passive=true,debounce=100}=options;this.listeners.set(id,{callback,debounce,lastCall: 0});if(this.listeners.size===1){window.addEventListener('scroll',this._handleScroll.bind(this),{passive});}},remove(id){this.listeners.delete(id);if(this.listeners.size===0){window.removeEventListener('scroll',this._handleScroll);}},_handleScroll(){if(!this.ticking){requestAnimationFrame(()=>{const now=Date.now();this.listeners.forEach((listener,key)=>{if(now-listener.lastCall>=listener.debounce){listener.callback();listener.lastCall=now;}});this.ticking=false;});this.ticking=true;}}};export default ScrollListener;